import Cocoa
import WebKit

class AppDelegate: NSObject, NSApplicationDelegate {
    var statusItem: NSStatusItem!
    var popover: NSPopover!
    var webView: WKWebView!
    var pollTimer: Timer?
    var lastStatusTs: Int = 0
    var pinned: Bool = false

    func applicationDidFinishLaunching(_ notification: Notification) {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        if let button = statusItem.button {
            button.title = "🤖"
            button.action = #selector(togglePopover(_:))
            button.target = self
            button.sendAction(on: [.leftMouseUp, .rightMouseUp])
        }

        let config = WKWebViewConfiguration()
        config.preferences.setValue(true, forKey: "allowFileAccessFromFileURLs")
        webView = WKWebView(frame: NSRect(x: 0, y: 0, width: 480, height: 380), configuration: config)

        // Auto-detect directory: PixelPet.app/Contents/MacOS/PixelPet → go up 3 levels to folder containing .app
        let execURL = Bundle.main.executableURL!
        let petDir = execURL.deletingLastPathComponent().deletingLastPathComponent().deletingLastPathComponent().deletingLastPathComponent().path
        let htmlPath = petDir + "/_pet.html"
        try! self.html.write(toFile: htmlPath, atomically: true, encoding: .utf8)
        let htmlURL = URL(fileURLWithPath: htmlPath)
        let dirURL = URL(fileURLWithPath: petDir)
        webView.loadFileURL(htmlURL, allowingReadAccessTo: dirURL)

        let vc = NSViewController()
        vc.view = webView

        popover = NSPopover()
        popover.contentSize = NSSize(width: 480, height: 380)
        popover.behavior = .transient
        popover.contentViewController = vc

        // JS handles polling via fetch now
    }

    @objc func pollStatus() {
        let execURL2 = Bundle.main.executableURL!
        let petDir2 = execURL2.deletingLastPathComponent().deletingLastPathComponent().deletingLastPathComponent().deletingLastPathComponent().path
        let path = petDir2 + "/status.json"
        guard let data = try? Data(contentsOf: URL(fileURLWithPath: path)),
              let str = String(data: data, encoding: .utf8) else { return }
        // Parse ts as string to avoid Int precision issues
        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let state = json["state"] as? String else { return }
        // ts might be Int or String
        let tsVal: String
        if let tsInt = json["ts"] as? Int {
            tsVal = String(tsInt)
        } else if let tsStr = json["ts"] as? String {
            tsVal = tsStr
        } else {
            tsVal = str // use whole content as change key
        }
        let tsHash = tsVal.hashValue
        if tsHash == lastStatusTs { return }
        lastStatusTs = tsHash
        let tool = (json["tool"] as? String) ?? ""
        DispatchQueue.main.async {
            let js = "if(typeof setToolState==='function'){setToolState('\(state)','\(tool)');'ok'}else{'no func'}"
            self.webView.evaluateJavaScript(js) { result, error in
                if let error = error {
                    NSLog("PixelPet JS error: \(error)")
                }
            }
        }
    }

    @objc func togglePopover(_ sender: Any?) {
        let event = NSApp.currentEvent
        // Right-click toggles pin mode
        if event?.type == .rightMouseUp {
            pinned = !pinned
            popover.behavior = pinned ? .applicationDefined : .transient
            if let button = statusItem.button {
                button.title = pinned ? "📌" : "🤖"
            }
            if pinned && !popover.isShown {
                if let button = statusItem.button {
                    popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
                }
            }
            return
        }
        // Left-click toggles popover
        if popover.isShown {
            popover.performClose(sender)
        } else if let button = statusItem.button {
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
        }
    }

    let html = """
    <!DOCTYPE html>
    <html>
    <head>
    <meta charset="UTF-8">
    <style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:#1a150f;overflow:hidden;user-select:none}
    .wrap{position:relative;width:480px;height:360px;overflow:hidden}
    .bg{position:absolute;top:0;left:0;width:100%;height:100%;
      background-image:url('data:image/png;base64,');
      background-size:cover;background-position:center;
      image-rendering:pixelated}
    .no-bg{position:absolute;top:0;left:0;width:100%;height:100%;
      display:flex;align-items:center;justify-content:center;
      font:13px 'Courier New',monospace;color:#666;text-align:center;
      line-height:1.8}
    canvas{position:absolute;top:0;left:0}
    .status{position:absolute;bottom:6px;left:50%;transform:translateX(-50%);
      background:rgba(0,0,0,0.75);color:#88cc66;font:10px 'Courier New',monospace;
      padding:3px 14px;border-radius:6px;letter-spacing:1px;white-space:nowrap;
      border:1px solid rgba(136,204,102,0.25);z-index:10}
    .controls{position:absolute;top:6px;right:6px;z-index:10;display:flex;gap:4px}
    .ctrl-btn{background:rgba(0,0,0,0.6);color:#aaa;border:1px solid rgba(255,255,255,0.15);
      font:9px monospace;padding:2px 6px;border-radius:4px;cursor:pointer}
    .ctrl-btn:hover{color:#fff;border-color:rgba(255,255,255,0.4)}
    </style>
    </head>
    <body>
    <div class="wrap">
      <div class="bg" id="bg"></div>
      <div class="no-bg" id="noBg">把背景图 bg.png 放到<br>和 PixelPet.app 同一个文件夹<br>然后重启 app<br><br>支持 PNG / JPG<br>推荐尺寸 480×360</div>
      <canvas id="c" width="480" height="360"></canvas>
      <div class="status" id="st">● 空闲中</div>
      <div class="controls">
        <div class="ctrl-btn" id="btnOverlay" title="显示/隐藏动画层" style="display:none">👁</div>
      </div>
    </div>
    <script>
    const C=document.getElementById('c'),X=C.getContext('2d');
    const ST=document.getElementById('st');
    const bgEl=document.getElementById('bg'),noBgEl=document.getElementById('noBg');
    const W=480,H=360;
    let tick=0,state='idle',bubbleTxt='',bubbleA=0;
    let overlayVisible=true;

    // Check if bg image loads
    let bgImg=new Image();
    bgImg.onload=()=>{ noBgEl.style.display='none'; };
    bgImg.onerror=()=>{ bgEl.style.display='none'; };
    bgImg.src='data:image/png;base64,';

    // Toggle overlay
    document.getElementById('btnOverlay').addEventListener('click',()=>{
      overlayVisible=!overlayVisible;
      C.style.display=overlayVisible?'block':'none';
      ST.style.display=overlayVisible?'block':'none';
    });

    const states={
      idle:{label:'● 空闲中',bubbles:['在等指令呢~','要聊点什么？','☕ 喝杯咖啡','准备好了！']},
      thinking:{label:'◆ 思考中',bubbles:['让我想想...','嗯...🤔','分析中📊','推理中...']},
      writing:{label:'✎ 写代码',bubbles:['哒哒哒⌨️','写得飞快！','代码不错~','快完了！']},
      reading:{label:'📖 读文件',bubbles:['看看这个...','原来如此！','读取中...','有发现👀']},
      running:{label:'▶ 执行中',bubbles:['跑起来了！','执行中⚡','等结果...','处理中...']},
      searching:{label:'🔍 搜索',bubbles:['找找看...','搜索中🔍','查一下...','翻代码！']},
      sleeping:{label:'😴 休息',bubbles:['💤','zzZ...','做梦中~']}
    };
    const stateOrder=['idle','thinking','writing','running','reading','searching','idle','sleeping'];
    let stIdx=0;

    // ====== ANIMATION OVERLAYS ======
    // These are drawn on top of your background image
    // You can configure positions to match your bg

    // Config: adjust these to match your background art
    const cfg = {
      // Screen as 4 corners (top-left, top-right, bottom-right, bottom-left)
      // Adjust these to match your bg.png monitor exactly
      screen: {
        tl:[150,122], tr:[189,104], br:[187,140], bl:[151,158],
        color:'#66ff88'
      },
      bubble: { x: 130, y: 58 },
      steam: { x: 218, y: 147 },
      cat: { x: 314, y: 262 },
      dust: { x: 180, y: 80, w: 120, h: 100 },
    };

    // Dust motes
    let dusts=[];
    for(let i=0;i<12;i++){
      dusts.push({
        x:cfg.dust.x+Math.random()*cfg.dust.w,
        y:cfg.dust.y+Math.random()*cfg.dust.h,
        vx:-0.15+Math.random()*0.3,
        vy:-0.1+Math.random()*0.2,
        phase:Math.random()*Math.PI*2
      });
    }

    function drawScreenOverlay(){
      let s=cfg.screen;
      let [tl,tr,br,bl]=[ s.tl, s.tr, s.br, s.bl ];

      // Center of screen for glow
      let cx=(tl[0]+tr[0]+br[0]+bl[0])/4;
      let cy=(tl[1]+tr[1]+br[1]+bl[1])/4;

      // Screen glow
      let sg=X.createRadialGradient(cx,cy,5,cx,cy,60);
      sg.addColorStop(0,'rgba(68,204,102,0.06)');
      sg.addColorStop(1,'rgba(68,204,102,0)');
      X.fillStyle=sg;
      X.fillRect(cx-60,cy-50,120,100);

      // Draw screen shape (parallelogram)
      X.save();
      X.beginPath();
      X.moveTo(tl[0],tl[1]);X.lineTo(tr[0],tr[1]);
      X.lineTo(br[0],br[1]);X.lineTo(bl[0],bl[1]);
      X.closePath();
      X.clip();

      // Fill screen bg (fully opaque to cover bg image)
      X.fillStyle='#0a1a0a';
      X.fill();

      // We need to compute an affine transform that maps a rectangle to the parallelogram
      // Map unit rect (0,0)-(1,0)-(1,1)-(0,1) to tl-tr-br-bl
      // Use tl as origin, tr-tl as x-axis, bl-tl as y-axis (affine, not full perspective)
      let ax=tr[0]-tl[0], ay=tr[1]-tl[1]; // x-axis
      let bx=bl[0]-tl[0], by=bl[1]-tl[1]; // y-axis

      // Screen virtual size for text layout
      let vw=40, vh=30;

      // Set transform: maps (0,0)-(vw,0)-(0,vh) to tl-tr-bl
      X.setTransform(ax/vw, ay/vw, bx/vh, by/vh, tl[0], tl[1]);

      // Scan lines
      X.fillStyle='rgba(0,255,80,0.04)';
      for(let y=0;y<vh;y+=2) X.fillRect(0,y,vw,1);

      // Text content - big and simple
      X.fillStyle=s.color;
      let lines,fontSize=8;
      switch(state){
        case 'writing':
          X.font='bold 9px monospace';
          lines=['WRITE',tick%8<4?'█':''];
          break;
        case 'running':
          X.font='bold 9px monospace';
          let b=Math.floor((tick%40)/5);
          lines=['RUN','▓'.repeat(b)+'░'.repeat(8-b)];
          break;
        case 'thinking':
          X.font='bold 9px monospace';
          lines=['THINK','.'.repeat((tick%12)/3+1|0)];
          break;
        case 'searching':
          X.font='bold 9px monospace';
          lines=['SEARCH',tick%6<3?'🔍':''];
          break;
        case 'sleeping':
          X.font='bold 9px monospace';
          lines=['SLEEP',tick%10<5?'z z':'Z Z'];break;
        case 'reading':
          X.font='bold 9px monospace';
          lines=['READ',tick%8<4?'>>':'> >'];break;
        default:
          X.font='bold 9px monospace';
          lines=['IDLE',tick%16<8?'>_':'> '];
      }
      lines.forEach((l,i)=>X.fillText(l,3,12+i*13));

      // Screen flicker
      if(tick%120<2){
        X.fillStyle='rgba(68,204,102,0.04)';
        X.fillRect(0,0,vw,vh);
      }

      X.restore();
    }

    function drawSteam(){
      let s=cfg.steam;
      for(let i=0;i<5;i++){
        let t=tick*0.04+i*1.4;
        let rise=i*5+Math.sin(t)*2;
        let sy=s.y-rise;
        let sx=s.x+Math.sin(t*0.7+i)*3;
        let a=0.4-i*0.06;
        let sz=1.5+i*0.4;
        if(a>0){
          X.fillStyle=`rgba(255,245,235,${a})`;
          X.beginPath();
          X.arc(sx,sy,sz,0,Math.PI*2);
          X.fill();
        }
      }
    }

    function drawDust(){
      dusts.forEach(d=>{
        d.x+=d.vx;
        d.y+=d.vy;
        d.phase+=0.02;
        if(d.x<cfg.dust.x||d.x>cfg.dust.x+cfg.dust.w||
           d.y<cfg.dust.y||d.y>cfg.dust.y+cfg.dust.h){
          d.x=cfg.dust.x+Math.random()*cfg.dust.w;
          d.y=cfg.dust.y+Math.random()*cfg.dust.h;
        }
        let a=Math.sin(d.phase)*0.15;
        if(a>0){
          X.fillStyle=`rgba(255,230,180,${a})`;
          X.fillRect(d.x,d.y,1.5,1.5);
        }
      });
    }

    function drawZZZ(){
      // Cat is always sleeping, independent of computer state
      let c=cfg.cat;
      let za=Math.abs(Math.sin(tick*0.03));
      X.globalAlpha=za*0.7;
      X.font='10px sans-serif';
      X.fillStyle='rgba(180,180,255,0.8)';
      X.fillText('z',c.x-5,c.y-8-za*6);
      X.font='7px sans-serif';
      X.globalAlpha=za*0.4;
      X.fillText('z',c.x+2,c.y-16-za*8);
      X.globalAlpha=1;
    }

    function drawClock(){
      let now=new Date();
      let h=String(now.getHours()).padStart(2,'0');
      let m=String(now.getMinutes()).padStart(2,'0');
      let blink=tick%60<30;
      let timeStr=h+(blink?':':' ')+m;

      // Position: left wall, above the lamp
      let cx=105,cy=82;

      // Clock body - small dark rectangle with slight perspective
      X.save();
      X.fillStyle='rgba(30,25,20,0.85)';
      X.fillRect(cx-16,cy-7,32,14);
      X.strokeStyle='rgba(80,70,55,0.6)';
      X.lineWidth=0.5;
      X.strokeRect(cx-16,cy-7,32,14);

      // Time text - pixel green like the monitor
      X.font='bold 9px monospace';
      X.fillStyle='rgba(100,255,130,0.9)';
      X.textAlign='center';
      X.fillText(timeStr,cx,cy+3);
      X.textAlign='left';
      X.restore();
    }

    function drawBubble(){
      if(bubbleA<0.01) return;
      let b=cfg.bubble;
      X.font='12px sans-serif';
      let m=X.measureText(bubbleTxt);
      let bw=m.width+20,bh=26;

      X.globalAlpha=bubbleA;
      // Dark bubble with green accent
      X.fillStyle='rgba(30,28,22,0.9)';
      X.beginPath();X.roundRect(b.x,b.y,bw,bh,8);X.fill();
      X.strokeStyle='rgba(136,204,102,0.3)';X.lineWidth=1;
      X.beginPath();X.roundRect(b.x,b.y,bw,bh,8);X.stroke();
      // Arrow
      X.fillStyle='rgba(30,28,22,0.9)';
      X.beginPath();
      X.moveTo(b.x+25,b.y+bh);X.lineTo(b.x+30,b.y+bh+7);X.lineTo(b.x+35,b.y+bh);
      X.fill();
      // Text
      X.fillStyle='rgba(200,230,180,0.9)';
      X.fillText(bubbleTxt,b.x+10,b.y+17);
      X.globalAlpha=1;
      bubbleA-=0.003;
    }

    function drawKeyboardGlow(){
      if(state!=='writing'&&state!=='running') return;
      // Subtle keyboard typing glow
      let kx=cfg.screen.x-10, ky=cfg.screen.y+cfg.screen.h+25;
      for(let i=0;i<8;i++){
        if((tick+i*3)%10<2){
          X.fillStyle='rgba(68,204,102,0.15)';
          X.fillRect(kx+i*8,ky,5,3);
        }
      }
    }

    function frame(){
      tick++;
      X.clearRect(0,0,W,H);
      if(!overlayVisible) return requestAnimationFrame(frame);

      drawScreenOverlay();
      drawSteam();
      drawDust();
      drawZZZ();
      drawKeyboardGlow();
      drawBubble();

      requestAnimationFrame(frame);
    }
    frame();

    // Hook-driven state updates
    let lastActivity=Date.now();
    let idleTimer=null;
    window.setToolState=function(newState,tool){
      if(idleTimer){clearTimeout(idleTimer);idleTimer=null;}
      if(newState===state) return;
      state=newState;
      lastActivity=Date.now();
      let s=states[state]||states.idle;
      let label=s.label;
      if(state!=='idle'&&state!=='sleeping'&&tool) label+=' ('+tool+')';
      ST.textContent=label;
      bubbleTxt=s.bubbles[Math.floor(Math.random()*s.bubbles.length)];
      bubbleA=1;
    };
    // Go to sleep after 60s of no activity
    setInterval(()=>{
      if(Date.now()-lastActivity>60000 && state!=='sleeping'){
        state='sleeping';
        let s=states.sleeping;
        ST.textContent=s.label;
        bubbleTxt=s.bubbles[Math.floor(Math.random()*s.bubbles.length)];
        bubbleA=1;
      }
    },5000);

    // Poll status.json every 500ms
    let lastRaw='',backToIdle=null;
    function pollFile(){
      let xhr=new XMLHttpRequest();
      try{
        xhr.open('GET','status.json',false);
        xhr.send();
        let txt=xhr.responseText||'';
        if(txt && txt!==lastRaw){
          lastRaw=txt;
          let d=JSON.parse(txt);
          if(d.state) window.setToolState(d.state,d.tool||'');
          // Auto back to idle after 3s of no new updates
          if(backToIdle) clearTimeout(backToIdle);
          backToIdle=setTimeout(()=>{window.setToolState('idle','');},8000);
        }
      }catch(e){}
    }
    setInterval(pollFile,500);

    // Calibration mode: click 4 corners of the screen
    let calibMode=false, calibPts=[], calibEl=null;

    document.getElementById('btnOverlay').addEventListener('dblclick',(e)=>{
      e.preventDefault();
      calibMode=!calibMode;
      calibPts=[];
      if(calibMode){
        ST.textContent='🔧 校准：依次点屏幕 左上→右上→右下→左下';
        ST.style.color='#ff8844';
      } else {
        ST.style.color='#88cc66';
      }
    });

    C.addEventListener('click',(e)=>{
      let rect=C.getBoundingClientRect();
      let x=Math.round((e.clientX-rect.left)*(W/rect.width));
      let y=Math.round((e.clientY-rect.top)*(H/rect.height));

      if(calibMode){
        calibPts.push([x,y]);
        let labels=['左上','右上','右下','左下'];
        if(calibPts.length<4){
          ST.textContent='🔧 已记录'+labels[calibPts.length-1]+' ('+x+','+y+') → 点击'+labels[calibPts.length];
        } else {
          // Done! Show the coordinates
          cfg.screen.tl=calibPts[0];
          cfg.screen.tr=calibPts[1];
          cfg.screen.br=calibPts[2];
          cfg.screen.bl=calibPts[3];
          let code='tl:['+calibPts[0]+'], tr:['+calibPts[1]+'], br:['+calibPts[2]+'], bl:['+calibPts[3]+']';
          ST.textContent='✅ '+code;
          ST.style.color='#88cc66';
          calibMode=false;
          // Also copy to clipboard
          navigator.clipboard.writeText(code).catch(()=>{});
          console.log(code);
        }
        return;
      }

      // Normal click
      const rr=['被点了！😆','别戳我~','在工作呢！','嘿！👋','☕ 喝咖啡？','你好呀~','别闹~🤣','专心！'];
      bubbleTxt=rr[Math.floor(Math.random()*rr.length)];
      bubbleA=1;
    });
    </script>
    </body>
    </html>
    """
}

let app = NSApplication.shared
app.setActivationPolicy(.accessory)
let delegate = AppDelegate()
app.delegate = delegate
app.run()
